import numpy as np

def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):

    best_node = None
    min_total_time = float('inf')

    for i, customer_pos in enumerate(unvisited_customers):
        travel_time = np.linalg.norm(cur_truck_pos - customer_pos) / truck_speed
        for truck_pos in all_truck_pos:
            if truck_pos is not cur_truck_pos:
                additional_travel_time = np.linalg.norm(truck_pos - customer_pos) / truck_speed
                if additional_travel_time < travel_time:
                    travel_time = additional_travel_time

        arrival_time = current_time + travel_time

        if arrival_time <= time_windows[i][1]:  # Within time window
            if arrival_time < time_windows[i][0]:  # Arrival before time window opens
                wait_time = time_windows[i][0] - arrival_time
                total_time = arrival_time + wait_time
            else:
                total_time = arrival_time

            if total_time < min_total_time:
                min_total_time = total_time
                best_node = i

    return best_node
